import{_ as n,o as a,c as p,ak as e}from"./chunks/framework.BQh-lcRV.js";const d=JSON.parse('{"title":"Sets","description":"","frontmatter":{},"headers":[],"relativePath":"guide/db/redis/sets.md","filePath":"guide/db/redis/sets.md","lastUpdated":1573567146000}'),i={name:"guide/db/redis/sets.md"};function l(t,s,c,o,r,g){return a(),p("div",null,[...s[0]||(s[0]=[e(`<h1 id="sets" tabindex="-1">Sets <a class="header-anchor" href="#sets" aria-label="Permalink to “Sets”">​</a></h1><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 往集合key中增加元素</span></span>
<span class="line"><span>sadd key value [value ...]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 删除集合中集为value等的元素</span></span>
<span class="line"><span># 返回值: 忽略不存在的元素后,真正删除掉的元素的个数</span></span>
<span class="line"><span>srem key value [value ...]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 返回并删除集合中key中1个随机元素</span></span>
<span class="line"><span>spop key</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 返回集合key中,随机的1个元素</span></span>
<span class="line"><span>srandmember key</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 判断value是否在key集合中, 是返回1,否返回0</span></span>
<span class="line"><span>sismember key value</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 返回集中中所有的元素</span></span>
<span class="line"><span>smembers key</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 返回集合中元素的个数</span></span>
<span class="line"><span>scard key</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 把source中的value删除,并添加到dest集合中</span></span>
<span class="line"><span>smove source dest value</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 求出key1 key2 key3 三个集合中的交集,并返回</span></span>
<span class="line"><span>sinter key1 key2 key3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; sadd s1 0 2 4 6</span></span>
<span class="line"><span>(integer) 4</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; sadd s2 1 2 3 4</span></span>
<span class="line"><span>(integer) 4</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; sadd s3 4 8 9 12</span></span>
<span class="line"><span>(integer) 4</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; sinter s1 s2 s3</span></span>
<span class="line"><span>1) &quot;4&quot;</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; sinter s3 s1 s2</span></span>
<span class="line"><span>&quot;4&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 求出key1 key2 key3 三个集合中的交集,并赋给dest</span></span>
<span class="line"><span>sinterstore dest key1 key2 key3</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span># 求出key1 key2 keyn的并集</span></span>
<span class="line"><span>sunion key1 key2.. Keyn</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 求出key1与key2 key3的差集</span></span>
<span class="line"><span>sdiff key1 key2 key3</span></span></code></pre></div><h3 id="有序集合" tabindex="-1">有序集合 <a class="header-anchor" href="#有序集合" aria-label="Permalink to “有序集合”">​</a></h3><blockquote><p>添加元素</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zadd key score1 value1 score2 value2 ..</span></span>
<span class="line"><span></span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zadd stu 18 lily 19 hmm 20 lilei 21 lilei</span></span>
<span class="line"><span>(integer) 3</span></span></code></pre></div><blockquote><p>删除集合中的元素</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zrem key value1 value2 ..</span></span></code></pre></div><blockquote><p>返回元素个数</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zcard key</span></span></code></pre></div><blockquote><p>返回[min,max] 区间内元素的数量</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zcount key min max</span></span></code></pre></div><blockquote><p>按照socre来删除元素,删除score在[min,max]之间的</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zremrangebyscore key min max</span></span>
<span class="line"><span></span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zremrangebyscore stu 4 10</span></span>
<span class="line"><span>(integer) 2</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zrange stu 0 -1</span></span>
<span class="line"><span>1) &quot;f&quot;</span></span></code></pre></div><blockquote><p>按排名删除元素,删除名次在[start,end]之间的</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zremrangebyrank key start end</span></span>
<span class="line"><span></span></span>
<span class="line"><span>redis&gt; ZADD myzset 1 &quot;one&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 2 &quot;two&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 3 &quot;three&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZREMRANGEBYRANK myzset 0 1</span></span>
<span class="line"><span>(integer) 2</span></span>
<span class="line"><span>redis&gt; ZRANGE myzset 0 -1 WITHSCORES</span></span>
<span class="line"><span>1) &quot;three&quot;</span></span>
<span class="line"><span>2) &quot;3&quot;</span></span></code></pre></div><blockquote><p>查询member的排名(升续 0名开始)</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zrank key member</span></span>
<span class="line"><span></span></span>
<span class="line"><span>redis&gt; ZADD myzset 1 &quot;one&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 2 &quot;two&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 3 &quot;three&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZRANK myzset &quot;three&quot;</span></span>
<span class="line"><span>(integer) 2</span></span>
<span class="line"><span>redis&gt; ZRANK myzset &quot;four&quot;</span></span>
<span class="line"><span>(nil)</span></span></code></pre></div><blockquote><p>查询 member的排名(降续 0名开始)</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zrevrank key memeber</span></span>
<span class="line"><span></span></span>
<span class="line"><span>redis&gt; ZADD myzset 1 &quot;one&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 2 &quot;two&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 3 &quot;three&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZREVRANK myzset &quot;one&quot;</span></span>
<span class="line"><span>(integer) 2</span></span>
<span class="line"><span>redis&gt; ZREVRANK myzset &quot;four&quot;</span></span>
<span class="line"><span>(nil)</span></span></code></pre></div><blockquote><p>把集合排序后,返回名次[start,stop]的元素</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ZRANGE key start stop [WITHSCORES]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>redis&gt; ZADD myzset 1 &quot;one&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 2 &quot;two&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 3 &quot;three&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZRANGE myzset 0 -1</span></span>
<span class="line"><span>1) &quot;one&quot;</span></span>
<span class="line"><span>2) &quot;two&quot;</span></span>
<span class="line"><span>3) &quot;three&quot;</span></span>
<span class="line"><span>redis&gt; ZRANGE myzset 2 3</span></span>
<span class="line"><span>1) &quot;three&quot;</span></span>
<span class="line"><span>redis&gt; ZRANGE myzset -2 -1</span></span>
<span class="line"><span>1) &quot;two&quot;</span></span>
<span class="line"><span>2) &quot;three&quot;</span></span></code></pre></div><blockquote><p>把集合降序排列,取名字[start,stop]之间的元素</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zrevrange key start stop</span></span>
<span class="line"><span></span></span>
<span class="line"><span>redis&gt; ZADD myzset 1 &quot;one&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 2 &quot;two&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZADD myzset 3 &quot;three&quot;</span></span>
<span class="line"><span>(integer) 1</span></span>
<span class="line"><span>redis&gt; ZREVRANGE myzset 0 -1</span></span>
<span class="line"><span>1) &quot;three&quot;</span></span>
<span class="line"><span>2) &quot;two&quot;</span></span>
<span class="line"><span>3) &quot;one&quot;</span></span>
<span class="line"><span>redis&gt; ZREVRANGE myzset 2 3</span></span>
<span class="line"><span>1) &quot;one&quot;</span></span>
<span class="line"><span>redis&gt; ZREVRANGE myzset -2 -1</span></span>
<span class="line"><span>1) &quot;two&quot;</span></span>
<span class="line"><span>2) &quot;one&quot;</span></span></code></pre></div><blockquote><p>集合(升续)排序后,取score在[min,max]内的元素, 并跳过 offset个, 取出N个</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zrangebyscore  key min max [withscores] limit offset N</span></span>
<span class="line"><span></span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zadd stu 1 a 3 b 4 c 9 e 12 f 15 g</span></span>
<span class="line"><span>(integer) 6</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zrangebyscore stu 3 12 limit 1 2 withscores</span></span>
<span class="line"><span>1) &quot;c&quot;</span></span>
<span class="line"><span>2) &quot;4&quot;</span></span>
<span class="line"><span>3) &quot;e&quot;</span></span>
<span class="line"><span>4) &quot;9&quot;</span></span></code></pre></div><blockquote><p>求key1-keyn的交集</p></blockquote><p>求key1,key2的交集,key1,key2的权重分别是 weight1,weight2 聚合方法用: sum |min|max 聚合的结果,保存在dest集合内</p><p>注意: weights ,aggregate如何理解? 答: 如果有交集, 交集元素又有socre,score怎么处理? Aggregate sum-&gt;score相加 , min 求最小score, max 最大score</p><p>另: 可以通过weigth设置不同key的权重, 交集时,socre * weights</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>zinterstore destination numkeys key1 [key2 ...] </span></span>
<span class="line"><span>[WEIGHTS weight [weight ...]] </span></span>
<span class="line"><span>[AGGREGATE SUM|MIN|MAX]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>详见下例</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zadd z1 2 a 3 b 4 c</span></span>
<span class="line"><span>(integer) 3</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zadd z2 2.5 a 1 b 8 d</span></span>
<span class="line"><span>(integer) 3</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zinterstore tmp 2 z1 z2</span></span>
<span class="line"><span>(integer) 2</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zrange tmp 0 -1</span></span>
<span class="line"><span>1) &quot;b&quot;</span></span>
<span class="line"><span>2) &quot;a&quot;</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zrange tmp 0 -1 withscores</span></span>
<span class="line"><span>1) &quot;b&quot;</span></span>
<span class="line"><span>2) &quot;4&quot;</span></span>
<span class="line"><span>3) &quot;a&quot;</span></span>
<span class="line"><span>4) &quot;4.5&quot;</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zinterstore tmp 2 z1 z2 aggregate sum</span></span>
<span class="line"><span>(integer) 2</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zrange tmp 0 -1 withscores</span></span>
<span class="line"><span>1) &quot;b&quot;</span></span>
<span class="line"><span>2) &quot;4&quot;</span></span>
<span class="line"><span>3) &quot;a&quot;</span></span>
<span class="line"><span>4) &quot;4.5&quot;</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zinterstore tmp 2 z1 z2 aggregate min</span></span>
<span class="line"><span>(integer) 2</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zrange tmp 0 -1 withscores</span></span>
<span class="line"><span>1) &quot;b&quot;</span></span>
<span class="line"><span>2) &quot;1&quot;</span></span>
<span class="line"><span>3) &quot;a&quot;</span></span>
<span class="line"><span>4) &quot;2&quot;</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zinterstore tmp 2 z1 z2 weights 1 2</span></span>
<span class="line"><span>(integer) 2</span></span>
<span class="line"><span>redis 127.0.0.1:6379&gt; zrange tmp 0 -1 withscores</span></span>
<span class="line"><span>1) &quot;b&quot;</span></span>
<span class="line"><span>2) &quot;5&quot;</span></span>
<span class="line"><span>3) &quot;a&quot;</span></span>
<span class="line"><span>4) &quot;7&quot;</span></span></code></pre></div>`,30)])])}const k=n(i,[["render",l]]);export{d as __pageData,k as default};
